"""
mkt-original — Genesis chapters 17-19
Run: python3 scripts/zc-original-genesis-17-19.py

Key linguistic coverage:
- Ch 17: El Shaddai name (v1); natan vs karat berit (v2); name-change etymologies (v5,15);
  berit olam (v7); circumcision vocabulary and karat/karat wordplay (v10-14); Isaac
  etymology from tsahaq (v17,19); emphatic "that very day" formula (v23)
- Ch 18: Theophany vocabulary (v1); adonay ambiguity (v3); shub ashub double infinitive (v10);
  palah — too hard/marvelous (v14); kasah — shall I hide? (v17); yadativ covenantal
  election (v19); tsaddiq/rasha dialogue decrements (v23-32)
- Ch 19: Malakhim vs anashim shift (v1 vs 18:2); yada in sexual sense (v5,8);
  sanwerim (blindness, v11); mahah (lingering, v16); double-YHWH formula (v24);
  nabaht (look back, v26); zakar (God remembered Abraham, v29)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(source, book, data):
    p = ROOT / "data" / "commentary" / source / f"{book}.json"
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f"  wrote {p.relative_to(ROOT)}")

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_ORIGINAL = {
  "17": {
    "1": """<p><strong>ʾēl šadday</strong> — "God Almighty." The divine name <em>ʾēl šadday</em> appears here for the first time since 35:11 and is the characteristic name for God in the patriarchal narratives (17:1; 28:3; 35:11; 43:14; 48:3; 49:25; Exod 6:3 identifies it as the pre-Mosaic name alongside which YHWH was not fully disclosed). The etymology of <em>šadday</em> is disputed: BDB derives it from <em>šādad</em> (to overpower); Albright proposed the Akkadian <em>šadû</em> (mountain); another reading connects it to <em>šēḏ</em> (breast/nurture) suggesting divine sufficiency. The LXX consistently renders it <em>pantokrator</em> (almighty), which the tradition follows. <em>Hithallek lĕpānay</em> — "walk before me" — the Hithpael of <em>hālaḵ</em>, as in Enoch (5:22) and Noah (6:9); the reflexive stem indicates continuous, habitual, reciprocal movement in God's presence. <em>Tāmîm</em> — "blameless/complete" — not sinless perfection but moral integrity (cf. Noah in 6:9; Job 1:1; Ps 15:2).</p>""",
    "2": """<p><strong>ûnĕtannāh bĕrîtî</strong> — "and I will give/place my covenant." The verb here is <em>nātan</em> (to give), not the <em>kārat</em> (to cut) of chapter 15. In 15:18 YHWH "cut" (<em>kārat</em>) the covenant with Abram in the ceremony of passing through the animal pieces. Here the covenant is being "given" — its content specified and formalized in circumcision. The semantic difference: <em>kārat bĕrît</em> = the establishment-event; <em>nātan bĕrît</em> = the ongoing giving/granting of covenant relationship. <em>Wĕʾarbeh ʾōtĕḵā bimĕʾōḏ mĕʾōḏ</em> — "and I will multiply you greatly" — the double superlative <em>mĕʾōḏ mĕʾōḏ</em> ("very very much") is an emphatic intensifier; Hebrew uses reduplication for emphasis where English would use "exceedingly" or "greatly."</p>""",
    "3": """<p><strong>wayyippōl ʾaḇrām ʿal-pānāyw</strong> — "Abram fell on his face." The prostration posture (<em>nāpal ʿal-pānāyw</em>) is the standard response to theophany in the patriarchal narratives (17:3,17; cf. Josh 5:14; Ezek 1:28; Dan 8:17). The narrative then presents a dialogue structured by the "as for me... as for you" (<em>waʾănî... wĕʾattāh</em>) formula in vv4 and 9 — a covenant suzerain-vassal form where the sovereign states his obligations first and then the vassal's obligations follow. The same structure governs Exod 6:6-7 and Deut 4-5.</p>""",
    "4": """<p><strong>ʾāḇ hāmôn gôyim</strong> — "father of a multitude of nations." The phrase is a folk etymology for <em>ʾaḇrāhām</em> — the narrator connects <em>hāmôn</em> (multitude, crowd, noise) to the name. The historical etymology of Abraham is disputed; it may simply be a longer dialectal variant of <em>ʾaḇrām</em> meaning "exalted father" (in Amorite personal names, both forms exist). The covenant formula <em>ʾănî hinnēh</em> ("behold, I") places God as the initiating party — the covenant obligation runs from God to Abraham first.</p>""",
    "5": """<p><strong>wĕlōʾ yiqqārēʾ ʿôḏ ʾet-šimĕḵā ʾaḇrām wĕhāyāh šimĕḵā ʾaḇrāhām</strong> — "No longer will your name be called Abram, but your name will be Abraham." In the ANE, renaming by a superior marked a change in identity, status, and vocation (Pharaoh renames Joseph in 41:45; Nebuchadnezzar renames Daniel in Dan 1:7). The change from <em>ʾaḇrām</em> to <em>ʾaḇrāhām</em> is lexically minor — an inserted <em>hēh</em> — but the narrator supplies the theological freight: "father of many nations." The same pattern governs the renaming of Jacob to Israel (32:28; 35:10) and Simon to Peter (John 1:42). <em>Kî ʾāḇ hāmôn gôyim nĕtattîḵā</em> — the perfect tense "I have made you" (<em>nĕtattîḵā</em>) treats the future promise as already accomplished from God's perspective — a divine performative: the declaration creates the reality it names.</p>""",
    "6": """<p><strong>wĕhiprêtî ʾōtĕḵā bimĕʾōḏ mĕʾōḏ</strong> — "I will make you very, very fruitful." <em>Pārāh</em> (to be fruitful) echoes the creation blessing of 1:28 ("be fruitful and multiply") — the covenant promise resumes and particularizes the creation mandate in one family. <em>Ûmĕlāḵîm mimmĕḵā yēṣēʾû</em> — "and kings will come from you" — the royal dimension of the Abrahamic promise anticipates the Davidic covenant (2 Sam 7; cf. Gen 49:10 — the royal scepter in Judah). The three levels of the promise in v6 — fruitfulness, nations, kings — unfold in the structure of biblical history: the patriarchs become Israel (fruitfulness), Israel becomes a kingdom (nations), and David's line becomes the royal covenant (kings).</p>""",
    "7": """<p><strong>bĕrît ʿôlām</strong> — "everlasting covenant." <em>ʿôlām</em> (H5769) — long duration, from the distant past or future; in covenantal contexts it means "perpetual, ongoing, not-to-be-dissolved" rather than strictly "eternal" in a philosophical sense. The phrase <em>bĕrît ʿôlām</em> is used for the Noahic covenant (9:16), the Abrahamic covenant (17:7,13,19), the covenant of circumcision (17:13), the Sinai-Sabbath (Exod 31:16), the Davidic covenant (2 Sam 23:5), and the new covenant (Isa 55:3; 61:8; Jer 32:40). <em>Lihyôt lĕḵā lēʾlōhîm</em> — "to be to you as God" — the covenant formula; the same formulation as Exod 6:7 and throughout Deuteronomy. The bilateral structure of the covenant: God gives himself to Abraham; Abraham and seed give themselves to God.</p>""",
    "8": """<p><strong>ʾereṣ mĕgûreyḵā</strong> / <strong>ʾaḥuzzat ʿôlām</strong> — "the land of your sojourning" → "everlasting possession." <em>Māgôr</em> (sojourning, temporary residence) — Abraham is a resident alien in Canaan, not an owner. The promise is that this temporary dwelling-place will become permanent inheritance. <em>ʾAḥuzzāh</em> (possession, holding) — a legal term for real property; used throughout Leviticus for land rights. The tension between <em>māgôr</em> (sojourner) and <em>ʾaḥuzzāh</em> (permanent possession) generates the theological theme Hebrews exploits: the patriarchs remained sojourners even after the promise, "looking forward to the city that has foundations" (Heb 11:10,13-16).</p>""",
    "9": """<p><strong>wĕʾattāh ʾet-bĕrîtî tišmōr</strong> — "And as for you, you shall keep my covenant." The "as for you" (<em>wĕʾattāh</em>) marks the vassal's obligation in the covenant structure begun in v4 ("as for me"). <em>Šāmar</em> (to keep, guard, observe) — the standard term for covenant fidelity in Deuteronomy (Deut 4:2; 5:1,29; 6:2 etc.). The keeping of the covenant is not a condition for its establishment — God has already established it — but the expression of belonging to it. Verse 9 addresses Abraham directly; v10 extends to "you and your descendants," framing circumcision as the covenant's visible sign across generations.</p>""",
    "10": """<p><strong>zōʾt bĕrîtî... himmôl lākem kol-zāḵār</strong> — "This is my covenant... every male among you shall be circumcised." The verb <em>mûl</em> (H4135) is the dedicated term for circumcision; the broader verb <em>kārat</em> (to cut) is used for covenant-cutting but also for being "cut off" in v14. The sign of the covenant is enacted by the same root action — cutting — that established the covenant. The rite is not unique to Israel (Egyptian, Canaanite, and other ANE peoples practiced circumcision), but here it is given a distinctive covenantal meaning: marking the body as belonging to the covenant lineage. In the NT this distinctive covenantal significance is transferred to baptism (Col 2:11-12) and relocated from the body to the heart (Deut 10:16; 30:6; Jer 4:4; Rom 2:28-29).</p>""",
    "11": """<p><strong>ûnĕmalttem ʾēt bĕśar ʿorlĕtem wĕhāyāh lĕʾôt bĕrît bênî ûbênêkem</strong> — "You shall circumcise the flesh of your foreskins, and it shall be the sign of the covenant between me and you." <em>ʿOrlāh</em> (foreskin) — later takes on figurative meanings: "uncircumcised lips" (Exod 6:12), "uncircumcised ear" (Jer 6:10), "uncircumcised heart" (Lev 26:41; Jer 9:26; Ezek 44:9). <em>ʾÔt bĕrît</em> — "sign of the covenant" — <em>ʾôt</em> (H226) as covenant sign follows the rainbow (9:12-13) and will precede the blood on doorposts (Exod 12:13) and Sabbath (Exod 31:13,17). Each covenant sign is physical, visible, recurring, and carries the promise it signifies.</p>""",
    "12": """<p><strong>ûben-šĕmōnat yāmîm yimmôl lākem kol-zāḵār lĕdōrōtêkem</strong> — "At eight days old every male among you shall be circumcised for your generations." The eighth day is specified without explicit rationale in the text. Later tradition noted that eighth-day circumcision follows completion of one full seven-day cycle (including one Sabbath), entering a new cycle of seven. Medically, blood coagulation factors (vitamin K and prothrombin) reach optimal levels around day eight — a convergence the ancient text does not explain but that later readers have noted. The two categories <em>yĕlîḏ bayit</em> (born in the household) and <em>miknāt kesep</em> (bought with silver/money) include the entire household regardless of ethnic origin — the covenant encompasses all who dwell within its boundaries, anticipating the ingathering of the nations.</p>""",
    "13": """<p><strong>himmôl yimmôl yĕlîḏ bêtĕḵā ûmiknāt kaspĕḵā</strong> — "He must certainly be circumcised, the one born in your household and the one bought with your silver." The emphatic doubled verb (Niphal infinitive absolute + Niphal imperfect) <em>himmôl yimmôl</em> expresses absolute certainty and obligation — "he shall certainly be circumcised." <em>Wĕhāyĕtāh bĕrîtî biḇśarkem lĕḇĕrît ʿôlām</em> — "and my covenant shall be in your flesh as an everlasting covenant" — <em>bĕśar</em> (flesh) is the location of the covenant sign; the covenant is written not on stone tablets (which come later) but in the body.</p>""",
    "14": """<p><strong>wĕnĕkrĕtāh hannepeš hahiʾ mēʿammehā</strong> — "that person shall be cut off from his people." The wordplay here is dense: the covenant is established by cutting (<em>kārat</em>, 15:18); its sign is cutting (<em>mûl</em>, vv10-13); and those who refuse the cutting are themselves cut off (<em>kārat</em> in the Niphal, here). The vocabulary of covenant-making and covenant-breaking uses the same root — the one who refuses the covenant cut is subjected to the covenant curse cut. <em>Hannepeš hahiʾ</em> — "that person/soul" — <em>nepeš</em> (H5315) here = individual person, not disembodied soul; the noun functions as a demonstrative pronoun equivalent: "that one." The phrase <em>kārat min-hāʿām</em> (cut off from the people) is the formula for the most severe civil-religious penalty in the Mosaic law, applied to dozens of infractions in Leviticus and Numbers.</p>""",
    "15": """<p><strong>šārāy ʾišĕtĕḵā lōʾ-tiqrāʾ ʾet-šĕmāh šārāy kî śārāh šĕmāh</strong> — "As for Sarai your wife, you shall not call her name Sarai, but Sarah shall be her name." Both forms mean "princess/noblewoman" — <em>śārāy</em> is an archaic or dialectal form; <em>śārāh</em> is the standard form. Unlike the Abram→Abraham change, the semantic content does not shift; but the name renewal participates in the broader theme of her new identity as "mother of nations" in v16. The renaming is paired — Abraham and Sarah are renamed together — signaling that both partners are equally encompassed in the covenant promise of descendants.</p>""",
    "16": """<p><strong>ûḇēraḵtî ʾōtāh wĕgam nātatî mimmennāh lĕḵā bēn</strong> — "I will bless her and moreover I will give you a son by her." The <em>gam</em> ("also, moreover") emphasizes the addition to the promise — not just blessing in general but specifically a son through Sarah. <em>Wĕhāyĕtāh lĕgôyim malkê ʿammîm mimmennāh yihyû</em> — "she shall become nations; kings of peoples shall come from her." The phrase <em>malkê ʿammîm</em> ("kings of peoples") distinguishes a broader category than "kings of Israel" — the promise is explicitly universal. Sarah's role is not merely to bear Isaac but to be the mother of a lineage that reaches all peoples through the covenant chain.</p>""",
    "17": """<p><strong>wayyippōl ʾaḇrāhām ʿal-pānāyw wayyiṣḥāq wayyōʾmer bĕlibbô</strong> — "Abraham fell on his face and laughed; he said in his heart." <em>Wayyiṣḥāq</em> — "he laughed" — the verb <em>ṣāḥaq</em> is the root from which Isaac's name (<em>yiṣḥāq</em>) derives. But Abraham's laughter is "in his heart" (<em>bĕlibbô</em>) — interior, not a public repudiation. The narrator does not code the laughter negatively as he does Sarah's in 18:15 (which is rebuked); Abraham's laughter appears to be wonder and joy at the sheer magnitude of the promise rather than unbelief. The distinction matters for how the name "Isaac" functions: the one born from laughter vindicates the laugher.</p>""",
    "18": """<p><strong>lû yišmāʿēl yihyeh lĕpāneyḵā</strong> — "O that Ishmael might live before you!" The optative particle <em>lû</em> expresses a wish or longing ("O that! If only!"); this is Abraham's intercession for Ishmael — he wants the existing son to receive the covenant blessing. The phrase <em>yihyeh lĕpāneyḵā</em> ("live before you") parallels the covenant formula of v1 ("walk before me") — Abraham wishes Ishmael the same covenant life that God offered him. God's response in vv19-20 is not a rejection of Ishmael but a distinction: Ishmael will be blessed greatly, but the covenant (<em>bĕrît</em>) will pass through Isaac.</p>""",
    "19": """<p><strong>ûqārāʾtā ʾet-šĕmô yiṣḥāq</strong> — "you shall call his name Isaac." The name <em>yiṣḥāq</em> = "he laughs/he will laugh" — a Qal imperfect third person masculine singular of <em>ṣāḥaq</em>. The name commemorates both Abraham's laughter (17:17) and Sarah's (18:12) — the child of impossible promise is literally named after the incredulous laughter of his parents. <em>Wahăqimōtî ʾet-bĕrîtî ʾittô lĕḇĕrît ʿôlām</em> — "I will establish my covenant with him as an everlasting covenant." The verb <em>qûm</em> (Hiphil, to cause to stand/establish) is used for formally ratifying or upholding an existing covenant — God does not cut a new covenant with Isaac but establishes/confirms the one already cut with Abraham in ch 15.</p>""",
    "20": """<p><strong>ûlĕyišmāʿēl šĕmaʿtîḵā hinnēh bēraḵtî ʾōtô</strong> — "And as for Ishmael, I have heard you; behold, I have blessed him." <em>Šāmaʿ</em> (to hear) is the root of <em>yišmāʿēl</em> — "God hears" — so "I have heard you" is a double entendre: God hears Abraham's prayer for Ishmael, and the name Ishmael itself encapsulates this hearing. <em>Šĕnêm-ʿāśār nĕśîʾim yôlîḏ</em> — "he will father twelve princes" — a deliberately symmetrical promise: twelve princes for Ishmael (25:13-16) mirrors twelve sons/tribes for Israel. The parallel structure shows that Ishmael's blessing is generous and structured, even while the covenant passes through Isaac.</p>""",
    "21": """<p><strong>wĕʾet-bĕrîtî ʾāqîm ʾet-yiṣḥāq</strong> — "but my covenant I will establish with Isaac." The contrastive <em>wĕʾet</em> (but, and as for) sets the covenant in sharp distinction from the blessing: Ishmael receives the blessing (v20); Isaac receives the covenant. The verb <em>qāyam</em> (Hiphil of <em>qûm</em>) — "establish" — is applied specifically to the covenant with Isaac, not to Ishmael's great nation promise. The distinction between being blessed (<em>bāraḵ</em>) and being the covenant heir is the theological center of the election argument Paul uses in Romans 9:6-9 and Galatians 4:21-31.</p>""",
    "22": """<p><strong>wayyaʿal ʾĕlōhîm mēʿal ʾaḇrāhām</strong> — "God went up from Abraham." The language of divine ascent <em>wayyaʿal</em> (Qal imperfect of <em>ʿālāh</em>, to go up) implies that God's presence had come down to Abraham during the vision — the theophany ends with YHWH ascending as Abraham had prostrated himself during the encounter (vv3,17). The abrupt ending signals that the covenant content has been fully communicated — no lingering, no further discussion; the word of God accomplishes its purpose and the divine presence withdraws until the next encounter (ch 18).</p>""",
    "23": """<p><strong>bayyôm hazzeh</strong> — "on that very day." The phrase <em>bĕʿeṣem hayyôm hazzeh</em> ("on the bone of this day" = "on the very same day") is an emphatic temporal formula marking immediate, complete obedience. The same phrase marks the Exodus departure (Exod 12:17,41,51) and the Day of Atonement prohibitions (Lev 23:28-30). Abraham circumcises the entire household — Ishmael, the purchased servants, the home-born — on the same day God commanded it. The narrative emphasizes completeness: all males, all categories, immediate action. The obedience is as comprehensive as the command.</p>""",
    "24": """<p><strong>wĕʾaḇrāhām ben-tišʿîm wĕtēšaʿ šānāh bĕhimmōlô</strong> — "and Abraham was ninety-nine years old when he circumcised himself." The narrator records Abraham's age (99) and Ishmael's age (13) explicitly — the ages matter because they establish that circumcision for Abraham was a covenant-renewal act (not the rite of infancy), while Ishmael's circumcision at 13 pre-dates puberty but follows his naming and recognition as Abraham's son. The verb <em>bĕhimmōlô</em> (Niphal infinitive construct of <em>mûl</em>) — "in his being circumcised" — treats the act as passive: he was circumcised, not he circumcised himself; but verse 23 makes clear Abraham initiated it. The Niphal here emphasizes the state achieved rather than the act performed.</p>""",
    "25": """<p><strong>wĕyišmāʿēl bĕnô ben-šĕlōš-ʿeśrēh šānāh bĕhimmōlô</strong> — "And his son Ishmael was thirteen years old when he was circumcised." The age thirteen for Ishmael became significant in later Jewish tradition: the Mishnah and later halakha designate thirteen as the age of religious obligation (bar mitzvah). Whether the Genesis text intends this is uncertain, but the coincidence means that in later reading, Ishmael's circumcision at puberty became the type for the age of adult covenant responsibility. In the genealogy of 25:12-18, Ishmael's twelve sons represent a full legitimate nation — his circumcision at 13 includes him in the Abrahamic covenant sign even though the covenant itself passes to Isaac.</p>""",
    "26": """<p><strong>bĕʿeṣem hayyôm hazzeh nimmôl ʾaḇrāhām wĕyišmāʿēl bĕnô</strong> — "On that very day Abraham and his son Ishmael were circumcised." The formula <em>bĕʿeṣem hayyôm hazzeh</em> repeats from v23 — emphasizing simultaneity and completeness. Father and son circumcised on the same day — the covenant sign spans both generations immediately. The narrative does not record Sarah's reaction or any other response; the focus is entirely on Abraham's complete and immediate obedience. Heb 11:17-19 will later describe Abraham's obedience as grounded in the conviction that God can raise from the dead.</p>""",
    "27": """<p><strong>wĕkol-ʾanĕšê bêtô yĕlîḏ bayit ûmiknāt-kesep mēʾēt ben-nēḵār nimmōlû ʾittô</strong> — "And every male of his household, born in the house and bought with silver from a foreigner, were circumcised with him." The phrase <em>ben-nēḵār</em> (son of a foreigner/stranger) confirms that the covenant sign extends to non-Israelites within Abraham's household. The covenant community is not defined purely by blood descent but by household membership and covenant sign. This breadth anticipates the "mixed multitude" of the Exodus (Exod 12:38) and the inclusion of sojourners in Israel's covenant life (Lev 17:8-9; Num 15:14-16).</p>"""
  },
  "18": {
    "1": """<p><strong>wayyērāʾ ʾēlāyw YHWH bĕʾēlōnê mamrēʾ</strong> — "YHWH appeared to him at the oaks of Mamre." The Niphal of <em>rāʾāh</em> (to see) → <em>nĕraʾeh</em> = "was seen/appeared" is the standard theophany formula throughout the patriarchal narratives (12:7; 17:1; 26:2; 35:9; Exod 3:2,16). The narrator opens by identifying the visitors as YHWH's appearance; the ambiguity that follows (three men, one speaks as YHWH, two go to Sodom as angels) is intentional — the text invites the reader to see the divine identity in the human form. <em>Yōšēḇ peteḥ-hāʾōhel kĕḥōm hayyôm</em> — "sitting at the entrance of the tent in the heat of the day" — the temporal setting (midday rest) makes the urgency of Abraham's hospitality response more vivid: he runs at noon to meet strangers.</p>""",
    "2": """<p><strong>šĕlōšāh ʾănāšîm niṣṣāḇîm ʿālāyw</strong> — "three men standing near him." The word <em>ʾănāšîm</em> (men, human beings) is the narrator's description — 19:1 will identify two of them as <em>malākim</em> (angels/messengers). The text moves between the two designations without resolving the tension explicitly. <em>Wayyāroṣ liqrāʾtām mippeṯaḥ hāʾōhel</em> — "he ran to meet them from the entrance of the tent" — the running (<em>rûṣ</em>) and the subsequent series of actions (hurrying, running, hastening) create a picture of extravagant, urgent hospitality that the NT epistle to the Hebrews alludes to: "Do not neglect to show hospitality to strangers, for thereby some have entertained angels unawares" (Heb 13:2).</p>""",
    "3": """<p><strong>ʾăḏōnāy ʾim-nāʾ māṣāʾtî ḥēn bĕʿêneyḵā</strong> — "My Lord, if I have found favor in your eyes." The form <em>ʾăḏōnāy</em> — the pointed form with the special <em>qames</em> vowels — is the form traditionally reserved for the divine title (in distinction from <em>ʾăḏōnî</em>, "my lord," used of human superiors). Whether Abraham is addressing all three visitors or specifically the divine figure is debated; the use of <em>ʾăḏōnāy</em> suggests at least partial recognition of divine presence. <em>Ḥēn</em> (H2580, grace/favor) — to "find favor in the eyes of" is the standard idiom for receiving gracious attention from a superior (Noah in 6:8; Joseph in 39:4; the formula recurs throughout the Pentateuch). This may be the earliest use of the phrase in an explicitly theological register — Abraham appeals to YHWH's grace as the ground of his request for the divine presence to remain.</p>""",
    "4": """<p><strong>yuqqaḥ-nāʾ mĕʿaṭ-mayim wĕraḥăṣû raglêkem</strong> — "Let a little water be brought, and wash your feet." The foot-washing gesture in the ANE signaled a transition from the dusty road to domestic hospitality — the guest was received as a member of the household for the duration of the stay (cf. Luke 7:44; John 13:5). Abraham's word <em>mĕʿaṭ</em> ("a little") before "water" and <em>pat-leḥem</em> ("a morsel of bread") in v5 is deliberate understatement — what follows is three seahs of flour, a choice calf, curds, and milk. The understatement of offer followed by extravagant provision is a hospitality convention that signals social grace.</p>""",
    "5": """<p><strong>kî-ʿal-kēn ʿăḇartem ʿal-ʿaḇdĕkem</strong> — "since you have passed by your servant." The phrase <em>ʿāḇar ʿal</em> — "pass over/by" — when combined with the hospitality offer means "since you have condescended to come to your servant." The motive clause ("since you have come to me") grounds the hospitality in a recognition that the visitors' coming is itself a privilege, not a burden. <em>ʾAḥar taʿăḇōrû</em> — "and then you may go on your way" — the sequence is: wash, rest, eat, then proceed. The hospitality is not designed to delay or detain permanently but to honor the transition.</p>""",
    "6": """<p><strong>šĕlōš sĕʾîm qemet sōlet</strong> — "three seahs of fine flour." A <em>seʾāh</em> is approximately 7-8 liters; three seahs = roughly 22 liters of flour — enough for a significant feast, not a "morsel." The word <em>sōlet</em> (fine flour) is the word used in Leviticus for the finest grade of flour in grain offerings — the best quality. <em>Ûlōšî wĕʿăśî ʿuggôt</em> — "knead and make cakes." <em>ʿUggôt</em> (round cakes cooked on coals or in ashes, as in 1 Kgs 19:6) — a quick bread for immediate hospitality. The urgency of preparation matches the urgency of the welcome.</p>""",
    "7": """<p><strong>wĕʾel-habbāqār rāṣ ʾaḇrāhām wayyiqqaḥ ben-bāqār raḵ wāṭôḇ</strong> — "And to the herd Abraham ran and took a calf, tender and good." Again the verb <em>rûṣ</em> (to run) — Abraham is running, not walking, throughout the hospitality scene. The calf is described as <em>raḵ wāṭôḇ</em> — "tender and good" — a double quality specification meaning the best of the herd. He gives the calf to a servant who "hastened" (<em>waymahēr</em>) to prepare it — the urgency cascades down: master runs, servant hurries. The narrative's repeated emphasis on speed creates a picture of extravagant, urgent generosity.</p>""",
    "8": """<p><strong>wayyiqqaḥ ḥemʾāh wĕḥālāḇ ûben-habbāqār ʾăšer ʿāśāh wayyittēn lipnêhem wĕhûʾ-ʿōmēḏ ʿălêhem taḥat hāʿēṣ wayyōʾkēlû</strong> — "He took curds and milk and the calf that had been prepared, and set it before them. And he stood beside them under the tree while they ate." The menu — curds, milk, veal — is a genuine meal, not a symbolic gesture. Importantly, "they ate" (<em>wayyōʾkēlû</em>) — the narrative does not retreat from the physical reality of divine messengers eating; this is not a visionary meal. The narrator uses this to establish genuine presence. Abraham stands while they eat — the posture of a host, not a dining companion; he does not eat with them but serves. The scene of the divine eating in Abraham's tent is the background for the Emmaus meal (Luke 24:30-31) and the promise of eating with Christ (Rev 3:20).</p>""",
    "9": """<p><strong>ʾayyēh śārāh ʾišĕtĕḵā</strong> — "Where is Sarah your wife?" The question comes from the divine visitors who already know the answer — it is a question designed to draw Sarah into the encounter and to set up the announcement. The inquiry into Sarah's whereabouts parallels God's question to Adam ("Where are you?" 3:9) and to Cain ("Where is Abel your brother?" 4:9) — a divine question that is never a request for information but a summons to attention and response. <em>Hinnēh bāʾōhel</em> — "There, in the tent" — Abraham's answer simply locates her; the tent will become the site from which she hears the promise that changes everything.</p>""",
    "10": """<p><strong>šôḇ ʾāšûḇ ʾēleyḵā kāʿēt ḥayyāh</strong> — "I will surely return to you about this time next year." The Qal infinitive absolute + imperfect (<em>šôḇ ʾāšûḇ</em>) creates the emphatic certain-future: "I will certainly, without fail, return." This construction appears in the covenant promise contexts to stress absolute commitment (cf. 22:17; 26:28). <em>Kāʿēt ḥayyāh</em> — "at the living time" or "when the time revives" — a temporal idiom that means "at this time next year" (cf. 2 Kgs 4:16,17 of Elisha's promise to the Shunammite woman; both cases use the exact phrase). The speaker declares his specific intention to return — the personal return of the divine visitor is part of the promise.</p>""",
    "11": """<p><strong>wĕśārāh šāmĕʿāh peteḥ hāʾōhel wĕhûʾ ʾaḥărāyw</strong> — "Sarah was listening at the entrance of the tent behind him." The participle <em>šōmaʿat</em> (listening) captures her real-time reception of the conversation. The physical arrangement — she is at the tent entrance, behind Abraham — places her as overhearing what is spoken to Abraham. <em>Wĕʾaḇrāhām wĕśārāh zĕqēnîm</em> — "Abraham and Sarah were old, advanced in years" — the double qualification (<em>zĕqēnîm</em> and <em>bāʾîm bayyāmîm</em>) stresses the magnitude of the obstacle. <em>Ḥādal lihyôt lĕśārāh ʾōraḥ kannāšîm</em> — "the way of women had ceased for Sarah" — a circumlocution for menopause; the narrator is unambiguous that human reproduction is biologically impossible.</p>""",
    "12": """<p><strong>wattiṣḥaq śārāh bĕqirbiāh</strong> — "Sarah laughed to herself." The verb <em>ṣāḥaq</em> — the same root as Isaac's name — appears again (cf. Abraham's laughter in 17:17). Sarah's laughter is explicitly internal (<em>bĕqirbiāh</em>, within herself), but its content is quoted directly by God in v13 — YHWH has access to what is said within the heart. <em>ʾAḥarê bĕlōtî</em> — "after I have worn out" — <em>bālāh</em> (H1086) = to wear out, consume; used of old garments wearing out in Isa 51:6 and Deut 8:4; 29:5. Sarah's language is bleakly physical: her body has worn out. <em>Wĕʾăḏōnî zāqēn</em> — "and my lord is old" — Sarah's term for Abraham, <em>ʾăḏōnî</em> ("my lord"), reflects the household authority structure and is noted approvingly in 1 Pet 3:6.</p>""",
    "13": """<p><strong>lāmmāh zeh ṣāḥăqāh śārāh lēʾmōr</strong> — "Why did Sarah laugh, saying..." YHWH's question reveals omniscience: he heard the internal laughter that was not audible. The challenge is not punitive but corrective — making Sarah aware that her internal response has been heard and must be addressed. The question "Why?" invites Sarah to acknowledge the faith-failure rather than condemning her outright. The omniscience of YHWH over the interior life of the human heart (the <em>lēḇ</em>) is consistent throughout Scripture (Ps 139:1-4; 1 Sam 16:7; 1 Kgs 8:39; Jer 17:10; Rev 2:23).</p>""",
    "14": """<p><strong>hăyippālēʾ mēYHWH dāḇār</strong> — "Is anything too hard for YHWH?" The verb <em>pālāʾ</em> (H6381) — to be wonderful, extraordinary, surpassing — is used of divine acts that exceed human capacity: the plagues (Ps 78:12), divine love (Ps 139:6), and the divine name (Judg 13:18). The same root gives the noun <em>peleʾ</em> (wonder, miracle) used in Isa 9:6 as a name of the Messiah. The rhetorical question expects the answer "nothing" — and the form is repeated almost verbatim in Jer 32:27: "Behold, I am YHWH, the God of all flesh; is anything too hard for me?" Mary's Magnificat (Luke 1:37) echoes this: "For nothing will be impossible with God." <em>Lammôʿēḏ</em> — "at the appointed time" — <em>môʿēḏ</em> (assembly, appointed season) is the same word used for the festival calendar; the birth of Isaac will be on schedule according to God's appointed time.</p>""",
    "15": """<p><strong>wayyōʾmer lōʾ kî ṣāḥāqt</strong> — "He said, 'No, but you did laugh.'" YHWH's two-word correction (<em>lōʾ kî ṣāḥāqt</em>) refuses the denial and asserts the truth of what he heard. The flat denial followed by the unambiguous correction establishes that YHWH cannot be misled by face-saving denial. The narrative does not record further dialogue — the correction stands, Sarah does not argue again, and the encounter moves on. The absence of further rebuke or punishment suggests that the correction is complete in the naming of the truth: she laughed, she is told she laughed, the son to be born will bear the name of that laughter.</p>""",
    "16": """<p><strong>wayyāšuqpû miššām ʿal-pĕnê sĕḏom</strong> — "they looked toward Sodom from there." The verb <em>šāqap</em> (to look down upon, overlook) is used in vv16 and 28 — Abraham also "looks down" (<em>wayyaṣṣēp</em>) toward Sodom from Mamre in v28 after the destruction. The geographic vantage point (the hills of Hebron-Mamre overlook the Jordan Valley and the Dead Sea region) is accurate. <em>Wĕʾaḇrāhām hōlēk ʿimmām lĕšalĕḥām</em> — "and Abraham walked with them to send them off" — the verb <em>šilaḥ</em> (to send, dismiss) is the customary gesture of completed hospitality; the host escorts the guests to the road.</p>""",
    "17": """<p><strong>hămekaséh ʾănî mēʾaḇrāhām ʾăšer ʾănî ʿōśeh</strong> — "Shall I hide from Abraham what I am about to do?" The divine deliberation is cast in the form of an internal divine question — <em>hămekaséh</em> (the interrogative + Piel infinitive of <em>kāsāh</em>, to cover, hide). The Piel of <em>kāsāh</em> = to cover/conceal; the question is whether YHWH's covenant relationship with Abraham creates an obligation of disclosure. The same principle is stated in Amos 3:7: "Surely the Lord GOD does nothing without revealing his secret (<em>sôdô</em>) to his servants the prophets." The divine "deliberation" is a narrative device that establishes Abraham as a covenant partner, not merely a covenant recipient.</p>""",
    "18": """<p><strong>wĕniḇrĕḵû bô kol gôyê hāʾāreṣ</strong> — "and all nations of the earth shall bless themselves by him" (or: "shall be blessed through him"). The verb <em>bāraḵ</em> in the Niphal can be passive ("shall be blessed") or reflexive ("shall bless themselves by/in his name"). The same promise formula appears in 12:3 and 22:18 (where the Hithpael form is used, explicitly reflexive). Paul cites Genesis 12:3 and 18:18 in Galatians 3:8-9 as the "gospel announced beforehand," reading the promise as a passive blessing flowing from Christ to the nations. The LXX uses <em>eneulogēthēsontai</em> (will be blessed), supporting the passive reading that the NT adopts.</p>""",
    "19": """<p><strong>kî yĕdaʿtîw lĕmaʿan ʾăšer yĕṣawweh ʾet-bānāyw</strong> — "For I have known/chosen him, so that he will command his children." The verb <em>yāḏaʿ</em> (H3045) in the Qal perfect first person — "I have known him" — carries the full covenantal-elective sense: personal, relational, purposive knowing. Amos 3:2 uses the same construction: "You only have I known of all the families of the earth." The word goes beyond cognition to encompass election, commitment, and relationship. <em>Lĕmaʿan</em> ("so that/in order that") — the purpose clause makes the election teleological: YHWH chose Abraham so that Abraham would form a household ordered by covenant faithfulness — not for Abraham's own sake alone but for the formation of a community of justice and righteousness (<em>ṣĕdāqāh ûmišpāṭ</em>). The pairing <em>ṣĕdāqāh</em> (righteousness) and <em>mišpāṭ</em> (justice) is the characteristic Amos-Isaiah-Micah formula for covenant social ethics (Amos 5:24; Isa 1:17; Mic 6:8).</p>""",
    "20": """<p><strong>zaʿăqat sĕḏōm waʿămōrāh kî-rāḇāh</strong> — "The cry of Sodom and Gomorrah — because it is great." <em>Zaʿaqāh</em> (H2201, outcry, cry for help) — the same root as the cry of the oppressed in Egypt (Exod 2:23; 3:7,9). The "cry" that rises to God is typically the cry of those wronged and powerless — here it is the cry of Sodom's victims (Ezek 16:49-50 identifies the sin as pride, excess food, prosperous ease, and failure to help the poor and needy, plus the act of 19:5). <em>Wĕḥaṭṭāʾtām kî-kāḇĕḏāh mĕʾōḏ</em> — "and their sin, because it is very heavy" — <em>kāḇēḏ</em> (heavy, weighty) is the same word for Pharaoh's "heavy" heart in Exodus. Sin as weight or burden pressing on the relationship is a consistent metaphor.</p>""",
    "21": """<p><strong>ʾērĕḏāh-nnāʾ wĕʾerʾeh</strong> — "I will go down and see." YHWH announces a divine descent to investigate — a deliberate anthropomorphism that echoes 11:5 (God descending to see the tower of Babel) and 11:7 ("Let us go down and there confuse their language"). The descent language is part of the divine-judge metaphor: a just judge investigates before pronouncing verdict. <em>Hăkiṣṣaʿăqātiāh bāʾāh ʾēlay ʿāśû kālāh wĕʾim-lōʾ ʾēḏāʿāh</em> — "whether they have done altogether according to the outcry that has come to me; and if not, I will know." The conditional ("and if not, I will know") establishes that the judgment is not predetermined — YHWH investigates; the outcome depends on the investigation. This is the grammar of divine justice: heard evidence, investigation, verdict.</p>""",
    "22": """<p><strong>wĕhāʾănāšîm pānû miššām wayyēlĕḵû sĕḏōmāh wĕʾaḇrāhām ʿôḏennû ʿōmēḏ lipnê YHWH</strong> — "the men turned from there and went toward Sodom, but Abraham was still standing before YHWH." The contrast is sharp: the angels depart on their mission, but Abraham remains. <em>ʿōmēḏ lipnê YHWH</em> — "standing before YHWH" — the posture of a court official, petitioner, or intercessor. The phrase is used of prophetic and priestly ministry (Deut 10:8; 1 Kgs 17:1; Jer 15:1). Abraham's standing before YHWH is the posture of prayer about to be articulated in vv23-32.</p>""",
    "23": """<p><strong>wayyiggaš ʾaḇrāhām wayyōʾmar</strong> — "Abraham drew near and said." The verb <em>nāgaš</em> (to draw near, approach) is used for priestly approach to the altar (Exod 19:22; 28:43; Lev 10:3; Ezek 44:13-16) and for judicial approach — the advocate drawing near to plead a case. Abraham's approach to YHWH over Sodom is an act of intercession that positions him as both priest and advocate. <em>Hăʾap tissĕpeh ṣaddîq ʿim-rāšāʿ</em> — "Will you sweep away the righteous with the wicked?" <em>Sāpāh</em> (to sweep away) — the same word used in v24 for the whole place being swept away. The question is a legal one: does collective judgment honor the principle that each person is accountable for their own sin (Ezek 18:20; Deut 24:16)?</p>""",
    "24": """<p><strong>ʾûlay yēš ḥămišîm ṣaddîqim bĕtôk hāʿîr</strong> — "What if there are fifty righteous people in the city?" The term <em>ṣaddîq</em> (H6662, righteous) — from the root <em>ṣādaq</em> (to be right/straight/just) — is the standard term for the morally and legally upright person. The opening bid of fifty provides the starting point for the negotiation. The theological principle Abraham applies: the presence of the righteous creates a claim on God's mercy for the community they inhabit. This principle works the other way in Amos 5:3 (where too few righteous remain) and positively in Isa 37:35 (God defends Jerusalem for David's sake). The logic of corporate benefit from the righteous few underlies 1 Pet 2:9.</p>""",
    "25": """<p><strong>ḥālîlāh lĕḵā mēʿăśōt kaddāḇār hazzeh lĕhāmît ṣaddîq ʿim-rāšāʿ</strong> — "Far be it from you to do such a thing — to kill the righteous with the wicked." <em>Ḥālîlāh</em> (H2486) — an exclamation of moral repudiation, literally "profanation (be it from you)!" It occurs predominantly in the mouth of patriarchs and in prophetic rejection of unthinkable acts (Gen 44:7,17; Josh 22:29; 24:16; 1 Sam 12:23; 14:45; 20:2; Job 27:5). <em>Hăšōpēṭ kol-hāʾāreṣ lōʾ yaʿăśeh mišpāṭ</em> — "Shall not the Judge of all the earth do justice?" The epithet "Judge of all the earth" (<em>šōpēṭ kol-hāʾāreṣ</em>) makes the argument from YHWH's universal judicial character: justice is not just a preference but the defining attribute of the one who governs all peoples. The same attribute grounds the Psalms' confidence in divine vindication (Ps 7:8; 9:4,8; 50:6).</p>""",
    "26": """<p><strong>ʾim-ʾemṣāʾ biṣḏōm ḥămišîm ṣaddîqim bĕtôk hāʿîr wĕnāśāʾtî lĕkol-hamāqôm biʿăḇûrām</strong> — "If I find in Sodom fifty righteous within the city, I will spare the whole place for their sake." <em>Nāśāʾ</em> (to lift up, bear, forgive/spare) — the same verb used for bearing sin in the formula of absolution (Num 14:18-19; Ps 32:1,5; Isa 33:24; Mic 7:18). God will "bear" or "lift up" the city — the forensic acquittal of the whole based on the merit of the righteous few. <em>Biʿăḇûrām</em> — "for their sake" — the preposition <em>bĕ</em> + <em>ʿāḇar</em> (for the sake of, on account of): the righteous serve as the ground of the community's preservation.</p>""",
    "27": """<p><strong>hinnēh-nāʾ hôʾaltî lĕdabbēr ʾel-ʾăḏōnāy wĕʾānōḵî ʿāpār wāʾēper</strong> — "Behold, I have undertaken to speak to the Lord, though I am dust and ashes." Abraham's self-description <em>ʿāpār wāʾēper</em> ("dust and ashes") combines two terms for low estate and mortality: <em>ʿāpār</em> (dust, as in 2:7, 3:19 — the substance of human mortality) and <em>ʾēper</em> (ashes, the remains of burning — cf. Job 30:19; 42:6). The doubled humility formula frames the intercession as an act of audacious grace-dependence: Abraham knows he has no standing to argue with the divine judge, yet he proceeds because he has been given access. This combination is the foundation of prophetic and priestly intercession in the Hebrew tradition.</p>""",
    "28": """<p><strong>ʾûlay yaḥsĕrûn ḥămišîm haṣṣaddîqim ḥămiššāh</strong> — "What if the fifty righteous are lacking five?" The negotiation proceeds in decrements: 50→45→40→30→20→10. The descending series follows a pattern of pressing the divine generosity: each successful reduction reveals that God's willingness to spare is not merely proportional arithmetic but reflects a deep reluctance to destroy. The word <em>ḥāśēr</em> (to lack, be deficient) — "What if they are five short?" — frames the argument as whether God will be rigidly exact or generously rounding. The answer is always generous: <em>lōʾ ʾašḥît</em>, "I will not destroy."</p>""",
    "29": """<p><strong>ʾûlay yimmāṣĕʾûn šām ʾarbāʿîm wayyōʾmer lōʾ ʾeʿĕśeh biʿăḇûr hāʾarbāʿîm</strong> — "What if forty are found there? He said, I will not do it for the sake of forty." The pattern of intercession — question / divine concession — repeats five times (vv28-32). Each exchange follows the same grammar: Abraham proposes a hypothetical (<em>ʾûlay</em>, "what if?"); YHWH responds with the preservation formula. The consistent divine response shows that YHWH is not reluctant to spare — he is willing at every threshold Abraham names. The negotiation reveals not a God who must be argued into mercy but a God whose mercy is deeper than the questioner's asking.</p>""",
    "30": """<p><strong>ʾal-nāʾ yiḥar lāʾḏōnāy wăʾădabbērāh</strong> — "Oh let not the Lord be angry, and I will speak." Abraham's repeated apology for the audacity of further pressing (<em>ʾal-nāʾ yiḥar</em> — "let it not burn/be hot to the Lord") appears in vv30 and 32. The verb <em>ḥārāh</em> (H2734, to be hot/angry) — the idiom "it was hot to someone" = they were angered. Abraham's hedging of each new proposal with this apology marks the social asymmetry of the encounter: he is a petitioner before a sovereign, and each new request requires the acknowledgment of potential impertinence. That YHWH never shows anger validates the bold approach.</p>""",
    "31": """<p><strong>hinnēh-nāʾ hôʾaltî lĕdabbēr ʾel-ʾăḏōnāy ʾûlay yimmāṣĕʾûn šām ʿeśrîm</strong> — "Behold, I have undertaken to speak to the Lord — what if twenty are found there?" The fifth round of intercession. The verb <em>hôʾîl</em> (Hiphil of <em>yaʾal</em>, to undertake, be willing, presume to) — Abraham keeps acknowledging the audacity of each new step. The decrements show that Abraham is pressing toward the lower limit of what he thinks might actually be present in Sodom — ten may be the number he estimates for Lot's household (Lot, his wife, his daughters, their pledged husbands, and any other dependents). The intercession is not abstract but aimed at saving specific people.</p>""",
    "32": """<p><strong>ʾal-nāʾ yiḥar lāʾḏōnāy wăʾădabbĕrāh ʾaḵ-happaʿam ʾûlay yimmāṣĕʾûn šām ʿăśārāh</strong> — "Oh let not the Lord be angry, and I will speak just this once more — what if ten are found?" The final threshold: ten righteous. Ten is the minimum viable social unit in later rabbinic tradition (the <em>minyan</em> required for communal prayer) — likely reflecting this very passage. Abraham stops at ten, presumably because he cannot argue below the minimum that would constitute a community. That even ten are not found (only Lot and his family are extracted, and the sons-in-law refuse to flee) shows the depth of Sodom's corruption. The intercession is not in vain — Lot is saved — but the city falls.</p>""",
    "33": """<p><strong>wayyēlek YHWH kaʾăšer killāh lĕdabbēr ʾel-ʾaḇrāhām wĕʾaḇrāhām šāḇ limĕqōmô</strong> — "YHWH went when he had finished speaking to Abraham, and Abraham returned to his place." The narrative closes the intercession with a symmetrical departure: YHWH leaves, Abraham returns. The word <em>killāh</em> (Piel perfect of <em>kālāh</em>, to complete, finish) — when YHWH had "finished" — the conversation had a natural close; God did not end it abruptly. <em>Wayyāšāḇ limĕqōmô</em> — "he returned to his place" — Abraham goes back to Mamre; the intercession is complete and Abraham can only wait. The juxtaposition of the divine departure and Abraham's return marks the end of the mediatorial encounter that governed 18:16-33.</p>"""
  },
  "19": {
    "1": """<p><strong>wayyāḇōʾû šĕnê hammalʾāḵîm sĕḏōmāh bāʿereḇ</strong> — "The two angels arrived at Sodom in the evening." The narrative now calls the two figures <em>malʾāḵîm</em> (messengers/angels) — a title not used in ch 18, where they were <em>ʾănāšîm</em> (men). The shift marks a narrative distinction: at Mamre all three were "men"; once they proceed to Sodom, the two are identified as divine messengers on a specific mission. The third figure, who was YHWH himself, remains with Abraham for the intercession (18:22). <em>Wĕlôṭ yōšēḇ bĕšaʿar-sĕḏōm</em> — "Lot was sitting in the gateway of the city." Sitting in the gate (<em>šaʿar</em>) indicates civic status — the gate was where commerce, justice, and civic life took place (cf. Ruth 4:1-2; Prov 31:23). Lot has a position in Sodom's civic life, which explains his response to the visitors and the Sodomites' resentment of him.</p>""",
    "2": """<p><strong>wayyōʾmer hinneh ʾaḏōnay sûrû-nāʾ ʾel-bêt ʿaḇdĕkem</strong> — "He said, My lords, please turn aside to your servant's house." Lot addresses the visitors as <em>ʾăḏōnay</em> — but with the plural form <em>ʾăḏōnay</em>, which is different from the singular divine title Abraham used in 18:3. Lot's hospitality offer parallels Abraham's but is less extravagant — he offers shelter and a night's rest. <em>Wĕrakăṣû raglêkem wĕhiškamtem wăhălaktem lĕdarkĕkem</strong> — "wash your feet, and you may rise early and go on your way." The explicit mention of early departure ("rise early and go your way") suggests Lot already senses the danger of overnight visitors in Sodom.</p>""",
    "3": """<p><strong>wayyiṣṣar bām mĕʾōḏ wayyāsurû ʾēlāyw wayyāḇōʾû ʾel-bêtô</strong> — "but he pressed them strongly and they turned aside to him and entered his house." The verb <em>ṣûr</em> (to press, urge strongly) — the Qal imperfect with <em>mĕʾōḏ</em> (very much) indicates vigorous insistence; Lot had to overcome their initial refusal (v2: "No, we will spend the night in the square"). The urgency of Lot's pressing may reflect his knowledge of Sodom's danger to strangers. <em>Wayyaʿaś lāhem mišteh ûmaṣṣôt ʾāpāh wayyōʾkēlû</em> — "He made for them a feast and baked unleavened bread, and they ate." <em>Maṣṣôt</em> (unleavened bread) — the quick bread of urgent hospitality; the same bread will later mark the urgency of the Exodus departure (Exod 12:15-20,39).</p>""",
    "4": """<p><strong>ʾanĕšê hāʿîr ʾanĕšê sĕḏōm nāsabbû ʿal-habbayit minnāʿar wĕʿad-zāqēn kol-hāʿām miqqāṣeh</strong> — "the men of the city, the men of Sodom, surrounded the house, from young to old, all the people to the last man." The comprehensiveness of the description — "from young to old, all the people to the last man" (<em>miqqāṣeh</em>, from the end/extremity) — establishes that the violence is not a fringe element but the totality of Sodom's male population. The phrase "all the people to the last man" erases any possibility of a hidden righteous remnant inside the city that Abraham's intercession might have located. The verdict of Genesis 18:20-21 ("the outcry is great, their sin very heavy") is embodied: there are not even ten righteous.</p>""",
    "5": """<p><strong>wĕnēḏĕʿāh ʾōtām</strong> — "that we may know them." The verb <em>yāḏaʿ</em> (H3045) in its sexual sense — the same sense as 4:1 ("Adam knew his wife Eve") and 4:17 (Cain knew his wife). The demand to "know" the divine visitors sexually is not only a violation of the hospitality code (which protected guests absolutely in ANE culture) but a perversion of the term that is most central to covenant relationship in Genesis: the <em>yāḏaʿ</em> by which God "knows" Abraham (18:19) and by which covenant relationship is formed is here deployed as an instrument of violence and domination. The narrative names the sin with the covenant word turned to its opposite purpose.</p>""",
    "6": """<p><strong>wayyēṣēʾ ʾălêhem lôṭ happetĕḥāh wĕhaddelet sāgar ʾaḥărāyw</strong> — "Lot went out to them at the entrance and shut the door behind him." Lot places himself between his guests and the mob — the door shut behind him means he cannot retreat; he stands as the single barrier between the visitors and the crowd. The gesture is one of physical interposition in hospitality-defense, which in the ANE context was a matter of honor: to fail to protect a guest admitted to your house was a profound shame. Lot's inadequate solution (vv7-8) shows his moral confusion, but his instinct to protect the guests at personal risk is honored by the narrative.</p>""",
    "7": """<p><strong>wayyōʾmar ʾal-nāʾ ʾaḥay tārēʿû</strong> — "He said, 'My brothers, please do not do evil.'" The term <em>ʾaḥay</em> ("my brothers") is a social appeal to community solidarity — the same term he uses in the next verse to introduce his offer. The use of <em>rāʿaʿ</em> (to do evil, do harm) in the Hiphil — "do this evil" — names their demand as moral wrong. Lot does not try to argue that the visitors are divine messengers; he appeals on purely ethical grounds that the action is wrong.</p>""",
    "8": """<p><strong>hinnēh-nāʾ lî šĕtê ḇānôt ʾăšer lōʾ-yāḏĕʿû ʾîš</strong> — "Behold, I have two daughters who have not known a man." The verb <em>yāḏaʿ</em> returns immediately — "who have not known a man" is the negative form of the sexual idiom just used in v5. The two daughters who are "not known" are offered in place of the guests the mob wants to "know." Lot's offer is morally indefensible by any standard, including the Torah's later explicit protections of daughters (Lev 19:29; Deut 23:17). The text does not endorse Lot's proposal; it presents the moral bankruptcy of his situation — the hospitality code he is trying to honor has corrupted his moral judgment to the point of sacrificing his children. Peter's description of Lot as "righteous Lot, greatly distressed by the sensual conduct of the wicked" (2 Pet 2:7-8) acknowledges his relative righteousness without endorsing every choice.</p>""",
    "9": """<p><strong>wayyōʾmĕrû gĕš-hālĕʾāh wayyōʾmĕrû haʾeḥāḏ bāʾ-lāgûr wayyišpōṭ šāpôṭ</strong> — "They said, 'Stand back!' And they said, 'This fellow came to sojourn, and he would play the judge!'" The crowd's charge against Lot is revealing: he is a <em>gēr</em> (sojourner, resident alien) who has presumed to judge (<em>šāpaṭ</em>) the native population. The irony is double: (1) Lot's judgment of the mob's action as wrong is entirely correct; (2) God is about to judge Sodom with actual judicial authority (the very <em>mišpāṭ</em> that Abraham appealed to in 18:25). The mob's rage at Lot for "playing judge" reveals their rejection of any moral accountability — the defining condition that makes judgment inevitable.</p>""",
    "10": """<p><strong>wayyišlĕḥû hāʾănāšîm ʾet-yādām wayyāḇîʾû ʾet-lôṭ ʾălêhem habbayĕtāh</strong> — "but the men reached out their hands and brought Lot into the house to them." The divine visitors act to protect Lot — they extend their hands (<em>šālaḥ yāḏ</em>) to pull him in. The gesture of the outstretched hand reverses: the mob's reaching toward the door (v9: "they pressed hard against Lot and came near to break the door") is countered by the angels' reaching to rescue. The sequence — mob pressing in, angels pulling the endangered person away — is a rescue pattern that recurs in the angel narratives (Dan 6:22; Acts 12:7-11).</p>""",
    "11": """<p><strong>wĕʾet-hāʾănāšîm ʾăšer-peteḥ habbayit hikkû bĕsanwērîm miqqāṭōn wĕʿad-gāḏôl wayyilʾû limmĕṣōʾ happātaḥ</strong> — "And the men at the entrance of the house they struck with blindness, from small to great, so that they wearied themselves to find the entrance." The word <em>sanwĕrîm</em> (H5575, blindness) — a rare term appearing only here and in 2 Kings 6:18 (where the Aramean army is struck blind before Elisha); it may be a loanword from Akkadian. The deliberate ambiguity — physical blindness or disorientation — does not diminish their persistence: "they wearied themselves to find the entrance." The blindness does not produce repentance; the Sodomites keep groping for the door. Moral blindness and physical blindness compound each other — the judgment on the senses mirrors the judgment on the will.</p>""",
    "12": """<p><strong>ʾōd-mî lĕḵā pōh ḥātan ûḇāneyḵā ûḇĕnōteyḵā wĕkol ʾăšer-lĕḵā bāʿîr hôṣēʾ min-hammāqôm</strong> — "Have you anyone else here? Son-in-law, sons, daughters, or anyone you have in the city — bring them out of the place." The angels' urgency reverses the previous question structure: instead of Lot going out to protect the visitors, the visitors are now focused on getting Lot's household out. The completeness of the summons ("anyone else," all categories) mirrors the completeness of the destruction to come. The <em>māqôm</em> (the place) becomes the technical term for Sodom in its condemned status — the same word used in Abraham's intercession ("spare the whole <em>māqôm</em>," 18:24,26,28).</p>""",
    "13": """<p><strong>kî-mašḥîtîm ʾănaḥnû ʾet-hammāqôm hazzeh</strong> — "For we are about to destroy this place." The verb <em>šāḥat</em> (Hiphil, to destroy, ruin) — <em>mašḥîtîm</em> (the participle, indicating imminent action) — uses the same root as the "corruption" of Genesis 6:11-12 (<em>tišāḥēt hāʾāreṣ</em>, "the earth was corrupt/being destroyed"). The symmetry is intentional: the pre-flood narrative uses <em>šāḥat</em> for corruption/destruction; the Sodom narrative uses it for divine judgment. <em>Kî-gāḏĕlāh ṣaʿăqātām ʾet-pĕnê YHWH</em> — "for the outcry against them has grown great before YHWH" — the same cry (<em>ṣaʿaqāh</em>) that reached YHWH in 18:20 is here specified as the judicial basis for the destruction.</p>""",
    "14": """<p><strong>wayyēṣēʾ lôṭ wayyĕdabbēr ʾel-ḥătānāyw lōqĕḥê ḇĕnōtāyw wayyōʾmer qûmû ṣĕʾû min-hammāqôm hazzeh</strong> — "Lot went out and spoke to his sons-in-law, those who were pledged to marry his daughters, and said, 'Get up, leave this place.'" <em>Lōqĕḥê ḇĕnōtāyw</em> — "those who were taking his daughters" — the participle <em>lōqĕḥê</em> (ones taking) indicates pledged marriage, not yet consummated (the daughters are described as virgin in v8). <em>Wayhî kimĕṣaḥēq bĕʿênê ḥătānāyw</em> — "He seemed to his sons-in-law to be mocking." <em>Mĕṣaḥēq</em> — the Piel participle of <em>ṣāḥaq</em> — "jesting, laughing at." The same root as Isaac's name and Sarah's laughter. The word that named the miracle-child (the laughter of faith and wonder) is here used for incredulous dismissal of prophetic warning — the exact opposite of faithful response.</p>""",
    "15": """<p><strong>ûkĕmalĕʾat haššaḥar wayyāʾîṣû hammalʾāḵîm bĕlôṭ lēʾmōr qûm qaḥ ʾet-ʾišĕtĕḵā wĕʾet-šĕtê ḇĕnōteyḵā hanniṣṣāʾōt</strong> — "With the dawn the angels urged Lot, saying, 'Get up! Take your wife and your two daughters who are here.'" The verb <em>ʾûṣ</em> (Hiphil of <em>yāṣaʾ</em> in some readings; or a separate root meaning to press urgently) — "they urged" — the angels are not gentle; they apply pressure. <em>Hanniṣṣāʾōt</em> — "who are found/who are here" — the Niphal participle of <em>māṣāʾ</em> (to find); a pointer to the daughters who actually came with Lot, distinguishing them from the daughters pledged to the sons-in-law who remained. The escape is partial — not the full household, only those who are present and willing.</p>""",
    "16": """<p><strong>wayyitmahĕmah</strong> — "He lingered." The verb <em>māhah</em> (H4102, to delay, linger, tarry) appears only here in the Niphal in the entire Hebrew Bible — a rare word for a vivid and significant moment. Lot delays even as the city is about to be destroyed, even after the warning, even at dawn. <em>Wayyaḥăziqû hāʾănāšîm bĕyādô ûḇĕyad-ʾišĕtô ûḇĕyad šĕtê ḇĕnōtāyw bĕḥemlat YHWH ʿālāyw</em> — "the men seized his hand and the hand of his wife and the hands of his two daughters, in the mercy of YHWH upon him." <em>Bĕḥemlat YHWH</em> — "in/by the compassion/mercy of YHWH" — <em>ḥemlāh</em> (H2550, pity, compassion) is the reason stated for the angels' physical intervention. Lot does not save himself; YHWH's mercy hauls him out. The moment is the OT version of Jude 23: "save others by snatching them out of the fire."</p>""",
    "17": """<p><strong>hinnāṣēl ʿal-napšeḵā</strong> — "Flee for your life." The Niphal imperative of <em>mālaṭ</em> (to escape, deliver oneself) — "Deliver yourself!" — is a sharp, urgent command. <em>ʿAl-napšeḵā</em> — "for/upon your life" — <em>nepeš</em> here = life, the living being at stake. The command structure intensifies: <em>hinnāṣēl</em> (escape!), <em>ʾal-tabbēṭ ʾaḥăreyḵā</em> (don't look back!), <em>wĕʾal-taʿămōḏ</em> (don't stop!), <em>hinnāṣēl hāhārāh</em> (flee to the mountains!). Four imperatives in sequence create an urgent rhythm that the narrative slows down by recording Lot's further negotiation in vv18-20.</p>""",
    "18": """<p><strong>wayyōʾmer lôṭ ʾălêhem ʾal-nāʾ ʾăḏōnāy</strong> — "Lot said to them, 'Oh, no, my lords!'" The address <em>ʾăḏōnāy</em> — whether divine or merely respectful plural — marks Lot's desperation. His response to "flee to the mountains" is a counter-proposal: let him flee to a nearby small city instead. The verb <em>hinnāṣēl</em> (flee/escape, v17) returns in v19 as Lot applies it to himself: "your servant cannot escape (<em>yûkal ʾaḇdĕḵā lĕhinnāṣēl</em>) to the mountains." The one commanded to escape claims he cannot obey the specific command and negotiates the terms of his own rescue even during the rescue.</p>""",
    "19": """<p><strong>wĕʾattāh ʿāśîtāh ʿimmî ḥesed lĕhaḥăyôt ʾet-napšî</strong> — "and you have shown great kindness (<em>ḥesed</em>) to me in sparing my life." <em>Ḥesed</em> (H2617, loyal love, steadfast kindness) — the word appears in Lot's description of God's rescue: the angels' mercy is designated as <em>ḥesed</em>, the covenant-loyalty term. This is striking: Lot, who is on the margins of the covenant community (Abraham's nephew, not the covenant heir), experiences the covenant love of YHWH in his rescue. The grace of the rescue is <em>ḥesed</em> — not earned, not conditional on Lot's righteousness but on YHWH's character (cf. 24:12; Ruth 2:20; Ps 136).</p>""",
    "20": """<p><strong>hinnēh-nāʾ hāʿîr-hazzōʾt qĕrōḇāh lānûs šāmmāh wĕhiʾ miṣʿār</strong> — "Behold, this city is near enough to flee to, and it is small." Lot's request is built on the smallness of the city: <em>miṣʿār</em> (H4705, small, insignificant). The name Zoar (<em>ṣōʿar</em>) becomes a wordplay on <em>miṣʿār</em> — "small" — the city gets renamed after the quality Lot used to justify his request. The logic of Lot's plea: he is too weak (<em>ûnapšî</em>) to reach the mountains; the nearby small city is sufficient. He bargains for the minimum escape, not the maximum safety — a reflection of his diminished spiritual state compared to Abraham, who pressed YHWH at every threshold.</p>""",
    "21": """<p><strong>wayyōʾmer ʾēlāyw hinnēh nāśāʾtî pāneyḵā gam laddāḇār hazzeh</strong> — "He said to him, 'Behold, I grant you this favor also.'" <em>Nāśāʾ pānîm</em> (to lift up the face of someone) = to show favor, to grant a request — a technical idiom for the favorable reception of a petition (cf. Gen 32:21; Lev 19:15). The word <em>gam</em> ("also") points to a prior favor — the rescue itself was the first favor; this specific request for Zoar is an additional one. The angel's compliance despite the apparent delay shows divine flexibility in rescue: the goal is to save Lot, not to insist on a specific route.</p>""",
    "22": """<p><strong>mah ʾer ʾeʿĕśeh dāḇār ʿad-bōʾăḵā šāmmāh</strong> — "I cannot do anything until you arrive there." The divine self-limitation expressed here — "I cannot" (<em>lōʾ ʾûkal</em>) — is remarkable: the execution of judgment is suspended until the righteous person is out. This is not a limitation on divine power but a statement of divine moral order: the judge who is about to destroy the city will not act while the righteous are still inside (cf. the angel of death "passing over" the houses with blood on the doorposts in Exod 12:13,23). <em>ʿal-kēn qārāʾ šēm-hāʿîr ṣōʿar</em> — "Therefore the name of the city was called Zoar" — the etiological explanation of the name (from <em>miṣʿār</em>, smallness) is inserted here.</p>""",
    "23": """<p><strong>haššemeš yāṣāʾ ʿal-hāʾāreṣ wĕlôṭ bāʾ ṣōʿārāh</strong> — "The sun had come out over the land when Lot came to Zoar." The arrival of the sun marks the transition from the night-rescue to the daylight-judgment. The temporal precision — sun rises as Lot arrives — compresses the timeline: Lot barely makes it out. The narrative has been tracking time carefully: evening arrival (v1), night events (vv4-11), dawn urgency (v15), sun rising as Lot reaches safety (v23), then destruction (v24). The pacing produces the effect of a narrowly escaped catastrophe.</p>""",
    "24": """<p><strong>wĕYHWH himṭîr ʿal-sĕḏōm wĕʿal-ʿămōrāh goprit wāʾēš mēʾēt YHWH min-haššāmayim</strong> — "YHWH rained on Sodom and on Gomorrah sulfur and fire from YHWH out of the heavens." The double use of YHWH — "YHWH rained... from YHWH out of the heavens" — has been noted in the tradition since ancient times. Three interpretive options: (1) an archaic idiom or resumptive construction with no theological weight (the LXX renders it straightforwardly); (2) a vestige of older source material that the narrator preserves without harmonizing; (3) a deliberate theological statement distinguishing the divine presence on earth (the YHWH who walked with Abraham and whose angels were in Sodom) from the transcendent divine source in heaven (the YHWH from whom the judgment comes). The patristic tradition used v24 to support the distinction between the Word/Son (manifested among the patriarchs) and the Father (dwelling in the heavens). The Hebrew text at minimum allows and arguably invites that reading.</p>""",
    "25": """<p><strong>wayyahpōk ʾet-hehārîm hāʾēl wĕʾēt kol-hakkikkār wĕʾēt kol-yōšĕḇê hehārîm wĕṣemiḥat hāʾăḏāmāh</strong> — "He overthrew those cities and all the valley and all the inhabitants of the cities and what grew on the ground." The verb <em>hāpaḵ</em> (to overturn, overthrow) — "he overturned/subverted" — becomes the standard prophetic vocabulary for Sodom's destruction (Isa 13:19; Jer 49:18; 50:40; Amos 4:11 uses <em>hāpaḵtî</em> as a direct reference). The comprehensiveness — cities, valley, inhabitants, vegetation — matches the judgment oracle of Deut 29:23 ("the whole land brimstone and salt, nothing sown and nothing growing, no grass anywhere"). The destruction is total ecological as well as human.</p>""",
    "26": """<p><strong>waṯṭabbēṭ ʾištô mēʾaḥărāyw wattĕhî nĕṣîḇ melaḥ</strong> — "but his wife looked back, and she became a pillar of salt." The verb <em>nābaṭ</em> (to look, gaze) — Qal imperfect of <em>nbt</em> — she "looked" behind her (<em>mēʾaḥărāyw</em>, from behind him). The command had been explicit: "do not look back" (v17, <em>ʾal-tabbēṭ ʾaḥăreyḵā</em>). <em>Nĕṣîḇ melaḥ</em> — "a pillar of salt" — salt in Deut 29:23 is a marker of desolation; salt-destruction was sometimes performed on conquered cities as a symbol of permanent desolation (Judg 9:45). The fate of Lot's wife becomes a warning in the mouth of Jesus: "Remember Lot's wife" (Luke 17:32) — the backward look of longing for the condemned city is itself the spiritual condition that the judgment executes physically.</p>""",
    "27": """<p><strong>wayyaškem ʾaḇrāhām babbōqer ʾel-hammāqôm ʾăšer-ʿāmaḏ šām ʾet-pĕnê YHWH</strong> — "Abraham rose early in the morning to the place where he had stood before YHWH." The verse locates Abraham at the same spot where he conducted the intercession of 18:22-33. <em>ʿĀmaḏ ʾet-pĕnê YHWH</em> (stood before the face of YHWH) — the priestly/prophetic posture of intercession. Abraham's early rising (<em>wayyaškem</em>) — the same verb used for Abraham's early rising to the Moriah sacrifice (22:3) — signals the urgency of his concern. He returns to see the outcome of the intercession he offered the night before.</p>""",
    "28": """<p><strong>wayyašqēp ʿal-pĕnê sĕḏōm waʿămōrāh wĕʿal-kol-pĕnê ʾereṣ hakkikkār wayyarʾ wĕhinnēh ʿālāh qîṭōr hāʾāreṣ kĕqîṭōr hakkibšān</strong> — "He looked down toward Sodom and Gomorrah and toward all the land of the valley, and he saw dense smoke rising from the land like the smoke of a furnace." The verb <em>šāqap</em> (to look down/overlook) — Abraham looks from the highland of Mamre toward the valley. The smoke image <em>qîṭōr hakkibšān</em> (smoke of a furnace/kiln) is similar to the Sinai theophany (Exod 19:18, where Sinai smokes "like a furnace"). The smoke of judgment and the smoke of divine presence use the same vocabulary — both are signs of YHWH's powerful action, one of grace and one of wrath.</p>""",
    "29": """<p><strong>wayyizkōr ʾĕlōhîm ʾet-ʾaḇrāhām wayyĕšallaḥ ʾet-lôṭ mittôk hahăpēḵāh</strong> — "God remembered Abraham and sent Lot out of the midst of the overthrow." The verb <em>zāḵar</em> (H2142, to remember) — covenantal memory, not mere cognitive recall — is the key to Lot's salvation. God did not remember Lot; he remembered Abraham. Lot's rescue is grounded in Abraham's intercession and covenant status. The same theological structure governs Exod 2:24-25 (God remembered his covenant with Abraham, Isaac, and Jacob and acted to redeem Israel from Egypt). <em>Mittôk hahăpēḵāh</em> — "from the midst of the overthrow" — the word <em>hāpēḵāh</em> (the overturning) is the nominalform of <em>hāpaḵ</em> (v25); Lot was extracted from the very center of what God was overthrowing.</p>""",
    "30": """<p><strong>wayyēṣēʾ lôṭ miṣṣōʿar wayyēšeḇ bāhār ûšĕtê ḇĕnōtāyw ʿimmô kî yārēʾ lāšeḇet bĕṣōʿar</strong> — "Lot went up from Zoar and settled in the mountains with his two daughters, because he feared to stay in Zoar." Having negotiated specifically for Zoar as his refuge (vv19-21), Lot immediately abandons it out of fear. The irony undercuts his earlier confident bargaining: the city he said was "near enough" and argued for is abandoned as soon as he is in it. <em>Wayyēšeḇ bammĕʿārāh hûʾ ûšĕtê ḇĕnōtāyw</em> — "he lived in a cave, he and his two daughters" — the descent from Sodom's civic prominence (sitting in the gate, v1) to cave-dwelling is complete.</p>""",
    "31": """<p><strong>watōʾmer habbĕḵîrāh ʾel-haṣṣĕʿîrāh ʾāḇînû zāqēn ûʾîš ʾên bāʾāreṣ lāḇôʾ ʿālênû kĕdereḵ kol-hāʾāreṣ</strong> — "The older said to the younger, 'Our father is old, and there is no man in the land to come in to us after the manner of all the earth.'" <em>Kĕdereḵ kol-hāʾāreṣ</em> ("according to the way of all the earth") — the daughters' phrase for normal human reproduction. Their perception that the world has been destroyed (likely they think Sodom was the world) and that no men exist prompts the plan to preserve the family line. The motive is preservation of <em>zera</em> (seed/offspring) — the same covenantal term used for Abraham's promised seed (17:7,9,10). The daughters act out of a distorted version of covenantal concern, without regard for the means.</p>""",
    "32": """<p><strong>lĕḵāh našqeh ʾet-ʾāḇînû yayin wĕniškĕḇāh ʿimmô wĕnaḥăyeh mēʾāḇînû zāraʿ</strong> — "Come, let us make our father drink wine, and we will lie with him, so that we may preserve offspring through our father." <em>Nĕḥayyeh zāraʿ mēʾāḇînû</em> — "preserve/cause to live offspring from our father" — the Piel of <em>ḥāyāh</em> (to live, preserve alive) with <em>zāraʿ</em> (seed/offspring). The language of <em>zāraʿ</em> preservation is the language of the Abrahamic covenant (17:7-10), here inverted: rather than waiting for divine provision (as Sarah was told to do, and as Abraham would later do on Moriah), the daughters take matters into their own hands. The parallel to the Sarai/Hagar episode (ch 16 — taking a shortcut to secure <em>zāraʿ</em>) is deliberate.</p>""",
    "33": """<p><strong>wĕlōʾ-yāḏaʿ bĕšiḵḇāh ûbĕqûmāh</strong> — "and he did not know when she lay down or when she rose." The phrase <em>yāḏaʿ</em> — "he did not know" — brings the sexual idiom of the chapter full circle. Sodom's men demanded to "know" the visitors (v5); Lot's daughters were described as "not known by a man" (v8); now Lot "does not know" (<em>lōʾ yāḏaʿ</em>) what happened — a moral oblivion enabled by wine. The use of <em>yāḏaʿ</em> throughout this chapter brackets the entire Sodom narrative: the word that should signify covenantal relationship is used for assault (v5), for innocence (v8), and for violated consciousness (v33,35). The chapter ends on the same term it began with.</p>""",
    "34": """<p><strong>wayĕhî mimmāḥǎrāt wayyōʾmer habbĕḵîrāh ʾel-haṣṣĕʿîrāh hēn-šāḵaḇtî ʾemeš ʾet-ʾāḇî</strong> — "The next day the older said to the younger, 'Last night I lay with my father.'" <em>ʾEmeš</em> (yesterday, last night) — an adverb used in contexts of recent time. The older daughter reports the event factually, without expressed regret or moral evaluation. The narrative maintains the same factual, evaluative silence — it does not insert a narrator's condemnation but the consequences (Moab, Ammon) will speak through the rest of the biblical story.</p>""",
    "35": """<p><strong>wattāqom haṣṣĕʿîrāh gam-hîʾ wattiškaḇ ʿimmô wĕlōʾ-yāḏaʿ bĕšiḵḇāh ûbĕqûmāh</strong> — "The younger also arose and lay with him, and he did not know when she lay down or when she rose." The same formula repeated verbatim — <em>wĕlōʾ-yāḏaʿ bĕšiḵḥāh ûbĕqûmāh</em> — for the second night emphasizes the pattern. The doubled formula (vv33,35) has the effect of insisting on the parallelism: the act is recorded twice in the same words, closing off interpretive escape routes. Lot's unknowing is complete — wine and darkness create a moral vacancy that the text refuses to mitigate.</p>""",
    "36": """<p><strong>wattaharên šĕtê ḇĕnôt-lôṭ mēʾăḇîhen</strong> — "So both of Lot's daughters became pregnant by their father." The bare statement — without embellishment, without divine comment — records the outcome. The word <em>harah</em> (to conceive, become pregnant) — the same word used for Sarah (18:14 — "shall Sarah conceive?") and for the Exodus generation's births. Here it is stripped of covenantal framing: the pregnancy is the product of calculation and deception, not divine promise. The contrast with Sarah's divinely promised conception (18:14) and the miraculous births of the covenant line is stark.</p>""",
    "37": """<p><strong>wattēled habbĕḵîrāh bēn wattigrāʾ šĕmô môʾāḇ hûʾ ʾăḇî môʾāḇ ʿad-hayyôm</strong> — "The older bore a son and called his name Moab; he is the father of the Moabites to this day." <em>Môʾāḇ</em> — the folk etymology here implies "from father" (<em>mēʾāḇ</em>), making the name a transparent reference to the incestuous origin. The Moabites and Israelites will be in perpetual tension in the subsequent narrative — but the genealogy of Ruth will bring a Moabite woman into the Davidic line (Ruth 4:13-22; Matt 1:5), and the God of Israel will declare himself the God of Moab's redemption through that lineage.</p>""",
    "38": """<p><strong>wĕhaṣṣĕʿîrāh gam-hîʾ yālaḏāh bēn wattiqrāʾ šĕmô ben-ʿammî hûʾ ʾăḇî ḇĕnê-ʿammôn ʿad-hayyôm</strong> — "The younger also bore a son and called his name Ben-Ammi; he is the father of the Ammonites to this day." <em>Ben-ʿammî</em> = "son of my people/kin" — again the name encodes the incestuous relation (<em>ʿam</em> = kinsman/people). Both Moab and Ammon will be thorns to Israel (Deut 23:3-6 excludes them from the assembly to the tenth generation), yet in the canon Ammon also has a place — Naamah the Ammonite is Solomon's wife and mother of Rehoboam (1 Kgs 14:21,31), weaving the descendants of Lot's cave into the royal line. The chapter ends not with closure but with "to this day" — these nations exist, and the narrative of their origins is the explanation of both their kinship with Israel and their antagonism.</p>"""
  }
}

def main():
    existing = load_comm("mkt-original", "genesis")
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_ORIGINAL)
    save_comm("mkt-original", "genesis", existing)

    result = load_comm("mkt-original", "genesis")
    after_count = sum(len(v) for v in result.values())
    print(f"  Verses added: {after_count - before_count}")
    for ch in [17, 18, 19]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f"  Ch {ch}: {n} verses present")
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f"  Genesis total: {total_chs} chapters, {total_vv} verses with original data")
    print("Genesis 17-19 original written.")

if __name__ == "__main__":
    main()
